using System.Windows;using System.Windows.Threading;using System.Xml;using System.Xml.Linq;using System.Xml.Serialization;namespace BgCommon;/// <summary>/// 通用工具类，提供文件持久化、序列化、UI调度及系统时钟获取等功能./// </summary>public partial class CommonTool{    /// <summary>    /// 获取系统时间获取模式：0为默认，1为硬件时钟.    /// </summary>    private static int getTicksMode;    /// <summary>    /// 硬件时钟频率.    /// </summary>    private static long ticksFrequency;    /// <summary>    /// 硬件时钟计数.    /// </summary>    private static long ticksCounter;    /// <summary>    /// 当前系统上电时间，单位毫秒.    /// </summary>    private static long currentTicks;    /// <summary>    /// Gets 当前应用程序的调度器.    /// </summary>    public static Dispatcher Dispatcher => Application.Current?.Dispatcher ?? Dispatcher.CurrentDispatcher;    /// <summary>    /// 使用二进制格式将对象保存到指定文件.    /// </summary>    /// <typeparam name="T">对象类型.</typeparam>    /// <param name="data">要保存的数据对象.</param>    /// <param name="filePath">目标文件路径集.</param>    /// <param name="msg">异常或错误信息.</param>    /// <returns>保存成功返回 true，否则返回 false.</returns>    public static bool Save<T>(T data, string filePath, out string msg)    {        msg = string.Empty;        string temporaryFilePath = filePath + ".tmp";        try        {            using (var fileStream = new FileStream(temporaryFilePath, FileMode.Create, FileAccess.Write, FileShare.None))            {                var binaryFormatter = new BinaryFormatter();                fileStream.Seek(0, SeekOrigin.Begin);                binaryFormatter.Serialize(fileStream, data!);                fileStream.Flush(true);            }            // 原子性替换目标文件            if (File.Exists(filePath))            {                File.Delete(filePath);            }            File.Move(temporaryFilePath, filePath, true);        }        catch (Exception ex)        {            // 发生异常时清理残留的临时文件            if (File.Exists(temporaryFilePath))            {                File.Delete(temporaryFilePath);            }            msg = ex.Message;            return false;        }        return true;    }    /// <summary>    /// 从文件中读取并反序列化二进制数据.    /// </summary>    /// <typeparam name="T">期望的对象类型.</typeparam>    /// <param name="filePath">文件路径.</param>    /// <param name="data">输出反序列化后的数据对象.</param>    /// <param name="msg">错误信息.</param>    /// <returns>读取成功返回 true，否则返回 false.</returns>    public static bool Read<T>(string filePath, out T? data, out string msg)    {        msg = string.Empty;        data = default;        try        {            using var fileStream = new FileStream(filePath, FileMode.OpenOrCreate, FileAccess.Read, FileShare.None);            fileStream.Seek(0, SeekOrigin.Begin);            var binaryFormatter = new BinaryFormatter();            data = (T)binaryFormatter.Deserialize(fileStream);        }        catch (Exception ex)        {            msg = ex.Message;            return false;        }        return true;    }    /// <summary>    /// 尝试对对象进行二进制序列化测试.    /// </summary>    /// <param name="obj">要测试的对象.</param>    /// <returns>序列化成功返回 true，否则返回 false.</returns>    public static bool TrySerialize(object obj)    {        try        {            using var objectStream = new MemoryStream();            var formatter = new BinaryFormatter();            formatter.Serialize(objectStream, obj);            return true;        }        catch (OutOfMemoryException)        {            // 内存不足异常处理        }        catch (Exception)        {            // 其他序列化异常处理        }        return false;    }    /// <summary>    /// 通过二进制序列化方式实现对象的深拷贝.    /// </summary>    /// <typeparam name="T">对象类型.</typeparam>    /// <param name="obj">源对象.</param>    /// <returns>拷贝后的新对象.</returns>    public static T? DeepCopy<T>(T obj)    {        using var memoryStream = new MemoryStream();        try        {            // 序列化成流            var binaryFormatter = new BinaryFormatter();            binaryFormatter.Serialize(memoryStream, obj!);            memoryStream.Seek(0, SeekOrigin.Begin);            // 反序列化成对象            object returnObject = binaryFormatter.Deserialize(memoryStream);            return (T)returnObject;        }        catch (Exception ex)        {            Trace.TraceError($"DeepCopy异常:{ex}");            return default;        }    }    /// <summary>    /// 将对象以 XML 格式序列化到指定文件.    /// </summary>    /// <typeparam name="T">对象类型.</typeparam>    /// <param name="obj">要保存的对象.</param>    /// <param name="filename">文件名.</param>    /// <param name="msg">异常信息.</param>    /// <returns>序列化成功返回 true.</returns>    public static bool ObjectToXml<T>(T obj, string filename, out string msg)    {        msg = string.Empty;        try        {            var xmlWriterSettings = new XmlWriterSettings();            xmlWriterSettings.Indent = true;            xmlWriterSettings.OmitXmlDeclaration = true;            xmlWriterSettings.NewLineOnAttributes = true;            xmlWriterSettings.Encoding = System.Text.Encoding.UTF8;            using var xmlWriter = XmlWriter.Create(filename, xmlWriterSettings);            var xmlSerializer = new XmlSerializer(typeof(T));            xmlSerializer.Serialize(xmlWriter, obj);            return true;        }        catch (Exception ex)        {            msg = ex.Message;            return false;        }    }    /// <summary>    /// 从 XML 文件中反序列化对象.    /// </summary>    /// <typeparam name="T">期望的对象类型.</typeparam>    /// <param name="filename">文件名.</param>    /// <param name="data">输出对象.</param>    /// <param name="msg">错误信息.</param>    /// <returns>反序列化成功返回 true.</returns>    public static bool XmlToObject<T>(string filename, out T? data, out string msg)        where T : class    {        msg = string.Empty;        data = default;        try        {            if (!File.Exists(filename))            {                msg = $"文件不存在！Path：{filename}";                return false;            }            using var xmlReader = XmlReader.Create(filename);            var xmlSerializer = new XmlSerializer(typeof(T));            data = (T?)xmlSerializer.Deserialize(xmlReader);            return true;        }        catch (Exception ex)        {            msg = ex.Message;            return false;        }    }    /// <summary>    /// 读取指定的 XML 文件并解析节点及其属性.    /// </summary>    /// <param name="filename">XML 文件名.</param>    /// <param name="nodes">输出节点名称列表.</param>    /// <param name="dicts">输出节点属性字典列表.</param>    public static void ReadXml(string filename, ref List<string> nodes, ref List<Dictionary<string, string>> dicts)    {        nodes.Clear();        dicts.Clear();        var xmlDocument = XDocument.Load(filename);        var rootElement = xmlDocument.Root;        foreach (var element in xmlDocument.Descendants())        {            string nodeName = element.Name.ToString();            var node = rootElement?.Element(nodeName);            if (node != null)            {                nodes.Add(nodeName);                var attributeDictionary = new Dictionary<string, string>();                foreach (var attribute in rootElement!.Elements(nodeName).Attributes())                {                    attributeDictionary.Add(attribute.Name.ToString(), attribute.Value);                }                dicts.Add(attributeDictionary);            }        }    }    /// <summary>    /// 将节点及属性列表写入指定的 XML 文件.    /// </summary>    /// <param name="filename">目标文件名.</param>    /// <param name="rootName">根节点名称.</param>    /// <param name="nodes">节点名称列表.</param>    /// <param name="dicts">节点属性列表.</param>    public static void WriteXml(string filename, string rootName, List<string> nodes, List<Dictionary<string, string>> dicts)    {        var xmlDocument = new XDocument();        var rootElement = new XElement(rootName);        xmlDocument.Add(rootElement);        for (int i = 0; i < nodes.Count; i++)        {            var nodeElement = new XElement(nodes[i]);            foreach (KeyValuePair<string, string> attributePair in dicts[i])            {                var attribute = new XAttribute(attributePair.Key, attributePair.Value);                nodeElement.Add(attribute);            }            rootElement.Add(nodeElement);        }        xmlDocument.Save(filename);    }    /// <summary>    /// 在 UI 线程上异步执行操作.    /// </summary>    /// <param name="callback">要执行的动作.</param>    /// <param name="priority">调度优先级.</param>    /// <returns>调度操作任务.</returns>    public static DispatcherOperation InvokeAsyncOnUI(Action callback, DispatcherPriority priority = DispatcherPriority.Normal)    {        return Application.Current.Dispatcher.InvokeAsync(callback, priority);    }    /// <summary>    /// 在 UI 线程上同步执行操作.    /// </summary>    /// <param name="callback">要执行的动作.</param>    /// <param name="priority">调度优先级.</param>    public static void InvokeOnUI(Action callback, DispatcherPriority priority = DispatcherPriority.Normal)    {        Application.Current.Dispatcher.Invoke(callback, priority);    }    /// <summary>    /// 强制分发当前消息队列中的所有消息（类似 WinForm 的 DoEvents）.    /// </summary>#if NETFRAMEWORK    // 仅在 .NET Framework 下保留特性，现代 .NET 自动忽略    [System.Security.Permissions.SecurityPermission(System.Security.Permissions.SecurityAction.Demand, Flags = SecurityPermissionFlag.UnmanagedCode, UnmanagedCode = true)]#endif    public static void DoEvents()    {        var frame = new DispatcherFrame();        Dispatcher.CurrentDispatcher.BeginInvoke(DispatcherPriority.Background, new DispatcherOperationCallback(ExitFrames), frame);        try        {            Dispatcher.PushFrame(frame);        }        catch (InvalidOperationException)        {            // 调度器已关闭等异常处理        }    }    /// <summary>    /// 初始化系统上电时间的获取模式.    /// </summary>    public static void InitTicks()    {        getTicksMode = 0;        if (QueryPerformanceCounter(ref ticksCounter))        {            if (QueryPerformanceFrequency(ref ticksFrequency))            {                if (ticksFrequency > 1000)                {                    getTicksMode = 1;                }            }        }    }    /// <summary>    /// 获取当前系统上电时间，单位毫秒.    /// </summary>    /// <returns>时间戳（毫秒）.</returns>    public static long GetCurTicks()    {        if (getTicksMode == 1)        {            if (QueryPerformanceCounter(ref ticksCounter))            {                if (QueryPerformanceFrequency(ref ticksFrequency))                {                    if (ticksFrequency > 1000)                    {                        currentTicks = ticksCounter * 1000 / ticksFrequency;                    }                }            }        }        else if (getTicksMode == 0)        {            currentTicks = GetTickCount();        }        return currentTicks;    }    /// <summary>    /// 退出 Dispatcher 帧，用于结束 DoEvents.    /// </summary>    /// <param name="frame">当前帧对象.</param>    /// <returns>返回 null.</returns>    private static object? ExitFrames(object frame)    {        ((DispatcherFrame)frame).Continue = false;        return null;    }    /// <summary>    /// 查询硬件性能计数器的当前值.    /// </summary>    /// <param name="lpPerformanceCount">输出计数值.</param>    /// <returns>成功返回 true.</returns>    [DllImport("kernel32.dll")]    private static extern bool QueryPerformanceCounter(ref long lpPerformanceCount);    /// <summary>    /// 查询硬件性能计数器的频率.    /// </summary>    /// <param name="performanceFrequency">输出频率值.</param>    /// <returns>成功返回 true.</returns>    [DllImport("kernel32.dll")]    private static extern bool QueryPerformanceFrequency(ref long performanceFrequency);    /// <summary>    /// 获取系统启动以来的毫秒数.    /// </summary>    /// <returns>毫秒数.</returns>    [DllImport("kernel32.dll")]    private static extern uint GetTickCount();}